parameters.jsonBody:
={
  "trigger_id": "{{ $json.trigger_id }}",
  "view": {
    "type": "modal",
    "callback_id": "daily_report",
    "private_metadata": "{{ JSON.stringify({channel_id: $json.channel_id, user_id: $json.user_id, user_name: $json.user_name}) }}",
    "title": { "type": "plain_text", "text": "📅 日報" },
    "submit": { "type": "plain_text", "text": "送信" },
    "close": { "type": "plain_text", "text": "閉じる" },
    "blocks": [
      {
        "type": "input",
        "block_id": "report_date",
        "label": { "type": "plain_text", "text": "日付" },
        "element": { "type": "datepicker", "action_id": "value", "initial_date": "{{ $now.toFormat('yyyy-MM-dd') }}" }
      },
      {
        "type": "input", "block_id": "call_count",
        "label": { "type": "plain_text", "text": "架電数" },
        "element": { "type": "number_input", "is_decimal_allowed": false, "action_id": "value", "min_value": "0" }
      },
      {
        "type": "input", "block_id": "apo_count",
        "label": { "type": "plain_text", "text": "アポ獲得数" },
        "element": { "type": "number_input", "is_decimal_allowed": false, "action_id": "value", "min_value": "0" }
      },
      {
        "type": "input", "block_id": "meeting_count",
        "label": { "type": "plain_text", "text": "商談数" },
        "element": { "type": "number_input", "is_decimal_allowed": false, "action_id": "value", "min_value": "0" },
        "optional": true
      },
      {
        "type": "input", "block_id": "contract_count",
        "label": { "type": "plain_text", "text": "契約数" },
        "element": { "type": "number_input", "is_decimal_allowed": false, "action_id": "value", "min_value": "0" },
        "optional": true
      },
      {
        "type": "input", "block_id": "highlights",
        "label": { "type": "plain_text", "text": "今日のハイライト" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true, "placeholder": { "type": "plain_text", "text": "3 行以内で要点を" } }
      },
      {
        "type": "input", "block_id": "tomorrow_plan",
        "label": { "type": "plain_text", "text": "明日の予定" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true },
        "optional": true
      },
      {
        "type": "input", "block_id": "blockers",
        "label": { "type": "plain_text", "text": "困りごと・相談" },
        "element": { "type": "plain_text_input", "action_id": "value", "multiline": true },
        "optional": true
      }
    ]
  }
}
